import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void basic() {
        String[] input = {"a", "bb", "ccc", "dd", "e"};
        Map<Integer, List<String>> result = new Solution().groupByLength(input);
        assertEquals(Set.of(1, 2, 3), result.keySet());
        assertEquals(List.of("a", "e"), result.get(1));
        assertEquals(List.of("bb", "dd"), result.get(2));
        assertEquals(List.of("ccc"), result.get(3));
    }

    @Test
    void empty() {
        Map<Integer, List<String>> result = new Solution().groupByLength(new String[]{});
        assertTrue(result.isEmpty());
    }

    @Test
    void singleWord() {
        Map<Integer, List<String>> result = new Solution().groupByLength(new String[]{"hello"});
        assertEquals(Set.of(5), result.keySet());
        assertEquals(List.of("hello"), result.get(5));
    }

    @Test
    void emptyStringWord() {
        // the empty string groups under key 0
        String[] input = {"", "a", ""};
        Map<Integer, List<String>> result = new Solution().groupByLength(input);
        assertEquals(Set.of(0, 1), result.keySet());
        assertEquals(List.of("", ""), result.get(0));
        assertEquals(List.of("a"), result.get(1));
    }

    @Test
    void allSameLength() {
        // adversarial: every word has the same length
        String[] input = {"cat", "dog", "ant", "fox"};
        Map<Integer, List<String>> result = new Solution().groupByLength(input);
        assertEquals(Set.of(3), result.keySet());
        assertEquals(List.of("cat", "dog", "ant", "fox"), result.get(3));
    }

    @Test
    void eachLengthDistinct() {
        // every word has a unique length — each bucket has exactly one element
        String[] input = {"a", "bb", "ccc", "dddd"};
        Map<Integer, List<String>> result = new Solution().groupByLength(input);
        assertEquals(Set.of(1, 2, 3, 4), result.keySet());
        assertEquals(List.of("a"), result.get(1));
        assertEquals(List.of("bb"), result.get(2));
        assertEquals(List.of("ccc"), result.get(3));
        assertEquals(List.of("dddd"), result.get(4));
    }

    @Test
    void preservesInsertionOrder() {
        // words of the same length must appear in input order
        String[] input = {"to", "be", "or", "not"};
        Map<Integer, List<String>> result = new Solution().groupByLength(input);
        assertEquals(List.of("to", "be", "or"), result.get(2));
        assertEquals(List.of("not"), result.get(3));
    }
}
